#include <stdio.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        long long *a = (long long*)malloc(n * sizeof(long long));
        for (int i = 0; i < n; ++i) scanf("%lld", &a[i]);
        int *ops = (int*)malloc(100000 * sizeof(int)); // max swaps ≤ 1e5
        int m = 0;
        for (int i = 1; i < n; ++i) {
            int j = i;
            while (j > 0 && a[j-1] > a[j]) {
                long long tmp = a[j-1]; a[j-1] = a[j]; a[j] = tmp;
                ops[m++] = j-1;
                --j;
            }
        }
        printf("%d\n", m);
        for (int i = 0; i < m; ++i) {
            if (i) printf(" ");
            printf("%d", ops[i]);
        }
        printf("\n");
        free(a);
        free(ops);
    }
    return 0;
}

