    while(T--){
        int n; cin>>n;
        vector<long long> a(n);
        for(int i=0;i<n;++i) cin>>a[i];
        vector<int> ops; ops.reserve(100000);
        for(int i=1;i<n;++i){
            int j=i;
            while(j>0 && a[j-1]>a[j]){
                swap(a[j-1],a[j]);
                ops.push_back(j-1);
                --j;
            }
        }
        cout<<ops.size()<<"\n";
        for(size_t i=0;i<ops.size();++i){
            if(i) cout<<' ';
            cout<<ops[i];
        }
        cout<<"\n";
    }
    return 0;
}

