import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int n = fs.nextInt();
            long[] a = new long[n];
            for (int i = 0; i < n; i++) a[i] = fs.nextLong();
            int[] ops = new int[100000]; // max swaps
            int m = 0;
            for (int i = 1; i < n; i++) {
                int j = i;
                while (j > 0 && a[j - 1] > a[j]) {
                    long tmp = a[j - 1]; a[j - 1] = a[j]; a[j] = tmp;
                    ops[m++] = j - 1;
                    j--;
                }
            }
            out.append(m).append('\n');
            for (int i = 0; i < m; i++) {
                if (i > 0) out.append(' ');
                out.append(ops[i]);
            }
            out.append('\n');
        }
        System.out.print(out.toString());
    }
    // Fast scanner for speed
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { return (int) nextLong(); }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
}

