const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
if (data.length === 0) process.exit(0);
const T = data[idx++];
let output = [];
for (let t = 0; t < T; ++t) {
  const n = data[idx++];
  const a = data.slice(idx, idx + n);
  idx += n;
  const ops = [];
  for (let i = 1; i < n; ++i) {
    let j = i;
    while (j > 0 && a[j - 1] > a[j]) {
      const tmp = a[j - 1];
      a[j - 1] = a[j];
      a[j] = tmp;
      ops.push(j - 1);
      --j;
    }
  }
  output.push(String(ops.length));
  output.push(ops.join(' '));
}
